import os
import io
import uuid
import json
import logging
import numpy as np
import pandas as pd
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
from flask import Flask, request, jsonify, send_file
from werkzeug.utils import secure_filename
from PIL import Image
from threading import Lock
import shutil
from datetime import datetime

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

UPLOAD_FOLDER = "uploads"
DATA_FOLDER = "training_data"
MODEL_FOLDER = "models"
METADATA_FILE = "metadata.json"
ALLOWED_IMAGE_EXTENSIONS = {"png", "jpg", "jpeg", "bmp", "gif"}
ALLOWED_CSV_EXTENSIONS = {"csv"}
MAX_CONTENT_LENGTH = 50 * 1024 * 1024  # 50MB max upload

for folder in [UPLOAD_FOLDER, DATA_FOLDER, MODEL_FOLDER]:
    os.makedirs(folder, exist_ok=True)

app.config["UPLOAD_FOLDER"] = UPLOAD_FOLDER
app.config["MAX_CONTENT_LENGTH"] = MAX_CONTENT_LENGTH

IMG_HEIGHT = 64
IMG_WIDTH = 64
IMG_CHANNELS = 3
BATCH_SIZE = 32
DEFAULT_EPOCHS = 10

model_lock = Lock()


class TrainingPipeline:
    def __init__(self):
        self.model = None
        self.class_names = []
        self.training_history = []
        self.contribution_log = []
        self.metadata = self._load_metadata()
        self._load_existing_model()

    def _load_metadata(self):
        if os.path.exists(METADATA_FILE):
            with open(METADATA_FILE, "r") as f:
                return json.load(f)
        return {
            "class_names": [],
            "total_samples": 0,
            "total_contributions": 0,
            "training_runs": 0,
            "last_trained": None,
            "contributors": [],
            "model_version": "0.0.0",
        }

    def _save_metadata(self):
        with open(METADATA_FILE, "w") as f:
            json.dump(self.metadata, f, indent=2, default=str)

    def _load_existing_model(self):
        model_path = os.path.join(MODEL_FOLDER, "latest_model.keras")
        if os.path.exists(model_path):
            try:
                self.model = keras.models.load_model(model_path)
                self.class_names = self.metadata.get("class_names", [])
                logger.info(f"Loaded existing model with classes: {self.class_names}")
            except Exception as e:
                logger.warning(f"Could not load existing model: {e}")
                self.model = None

    def _build_model(self, num_classes):
        model = keras.Sequential([
            layers.Input(shape=(IMG_HEIGHT, IMG_WIDTH, IMG_CHANNELS)),

            layers.Rescaling(1.0 / 255),

            layers.RandomFlip("horizontal"),
            layers.RandomRotation(0.1),
            layers.RandomZoom(0.1),

            layers.Conv2D(32, (3, 3), activation="relu", padding="same"),
            layers.BatchNormalization(),
            layers.MaxPooling2D((2, 2)),

            layers.Conv2D(64, (3, 3), activation="relu", padding="same"),
            layers.BatchNormalization(),
            layers.MaxPooling2D((2, 2)),

            layers.Conv2D(128, (3, 3), activation="relu", padding="same"),
            layers.BatchNormalization(),
            layers.MaxPooling2D((2, 2)),

            layers.Conv2D(256, (3, 3), activation="relu", padding="same"),
            layers.BatchNormalization(),
            layers.MaxPooling2D((2, 2)),

            layers.Flatten(),
            layers.Dense(256, activation="relu"),
            layers.Dropout(0.5),
            layers.Dense(128, activation="relu"),
            layers.Dropout(0.3),
            layers.Dense(num_classes, activation="softmax"),
        ])

        model.compile(
            optimizer=keras.optimizers.Adam(learning_rate=0.001),
            loss="sparse_categorical_crossentropy",
            metrics=["accuracy"],
        )
        return model

    def _preprocess_image(self, image_path):
        try:
            img = Image.open(image_path).convert("RGB")
            img = img.resize((IMG_WIDTH, IMG_HEIGHT))
            img_array = np.array(img, dtype=np.float32)
            return img_array
        except Exception as e:
            logger.error(f"Error preprocessing image {image_path}: {e}")
            return None

    def _validate_image(self, file_path):
        try:
            with Image.open(file_path) as img:
                img.verify()
            return True
        except Exception:
            return False

    def _sanitize_label(self, label):
        label = str(label).strip()
        label = "".join(c for c in label if c.isalnum() or c in (" ", "-", "_"))
        return label[:100]

    def load_csv_dataset(self, csv_path, image_column="image_path", label_column="label"):
        try:
            df = pd.read_csv(csv_path)

            if image_column not in df.columns or label_column not in df.columns:
                available = list(df.columns)
                return None, None, f"Required columns not found. Available: {available}"

            df = df.dropna(subset=[image_column, label_column])
            df[label_column] = df[label_column].apply(self._sanitize_label)
            df = df[df[label_column].str.len() > 0]

            images = []
            labels = []
            skipped = 0

            for _, row in df.iterrows():
                img_path = row[image_column]

                if not os.path.isabs(img_path):
                    csv_dir = os.path.dirname(os.path.abspath(csv_path))
                    img_path = os.path.join(csv_dir, img_path)

                img_path = os.path.realpath(img_path)
                if not img_path.startswith(os.path.realpath(UPLOAD_FOLDER)) and \
                   not img_path.startswith(os.path.realpath(DATA_FOLDER)):
                    skipped += 1
                    continue

                if not os.path.exists(img_path):
                    skipped += 1
                    continue

                if not self._validate_image(img_path):
                    skipped += 1
                    continue

                img_array = self._preprocess_image(img_path)
                if img_array is not None:
                    images.append(img_array)
                    labels.append(row[label_column])
                else:
                    skipped += 1

            if len(images) == 0:
                return None, None, "No valid images found in CSV"

            logger.info(f"Loaded {len(images)} images, skipped {skipped}")
            return np.array(images), labels, None

        except Exception as e:
            logger.error(f"Error loading CSV: {e}")
            return None, None, str(e)

    def load_directory_dataset(self):
        images = []
        labels = []

        if not os.path.exists(DATA_FOLDER):
            return np.array([]), [], "No training data directory found"

        for class_name in sorted(os.listdir(DATA_FOLDER)):
            class_dir = os.path.join(DATA_FOLDER, class_name)
            if not os.path.isdir(class_dir):
                continue

            for img_file in os.listdir(class_dir):
                img_path = os.path.join(class_dir, img_file)
                ext = img_file.rsplit(".", 1)[-1].lower() if "." in img_file else ""
                if ext not in ALLOWED_IMAGE_EXTENSIONS:
                    continue

                if not self._validate_image(img_path):
                    continue

                img_array = self._preprocess_image(img_path)
                if img_array is not None:
                    images.append(img_array)
                    labels.append(class_name)

        if len(images) == 0:
            return np.array([]), [], "No valid images in training data"

        return np.array(images), labels, None

    def _encode_labels(self, labels):
        unique_labels = sorted(list(set(labels)))
        label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
        encoded = np.array([label_to_idx[label] for label in labels])
        return encoded, unique_labels

    def train(self, images, labels, epochs=DEFAULT_EPOCHS, validation_split=0.2, contributor=None):
        with model_lock:
            try:
                if len(images) < 2:
                    return {"error": "Need at least 2 samples to train"}

                encoded_labels, class_names = self._encode_labels(labels)
                num_classes = len(class_names)

                if num_classes < 2:
                    return {"error": "Need at least 2 classes to train"}

                logger.info(f"Training with {len(images)} images, {num_classes} classes: {class_names}")

                needs_rebuild = (
                    self.model is None
                    or self.class_names != class_names
                )

                if needs_rebuild:
                    self.model = self._build_model(num_classes)
                    self.class_names = class_names

                indices = np.random.permutation(len(images))
                images = images[indices]
                encoded_labels = encoded_labels[indices]

                callbacks = [
                    keras.callbacks.EarlyStopping(
                        monitor="val_loss" if validation_split > 0 else "loss",
                        patience=5,
                        restore_best_weights=True,
                    ),
                    keras.callbacks.ReduceLROnPlateau(
                        monitor="val_loss" if validation_split > 0 else "loss",
                        factor=0.5,
                        patience=3,
                    ),
                ]

                actual_val_split = validation_split if len(images) >= 10 else 0.0

                history = self.model.fit(
                    images,
                    encoded_labels,
                    epochs=epochs,
                    batch_size=min(BATCH_SIZE, len(images)),
                    validation_split=actual_val_split,
                    callbacks=callbacks,
                    verbose=1,
                )

                model_path = os.path.join(MODEL_FOLDER, "latest_model.keras")
                self.model.save(model_path)

                version_parts = self.metadata.get("model_version", "0.0.0").split(".")
                version_parts[-1] = str(int(version_parts[-1]) + 1)
                new_version = ".".join(version_parts)

                self.metadata["class_names"] = class_names
                self.metadata["total_samples"] = int(len(images))
                self.metadata["training_runs"] = self.metadata.get("training_runs", 0) + 1
                self.metadata["last_trained"] = datetime.now().isoformat()
                self.metadata["model_version"] = new_version
                if contributor and contributor not in self.metadata.get("contributors", []):
                    self.metadata.setdefault("contributors", []).append(contributor)
                self._save_metadata()

                result = {
                    "status": "success",
                    "model_version": new_version,
                    "num_classes": num_classes,
                    "class_names": class_names,
                    "num_samples": len(images),
                    "epochs_completed": len(history.history["loss"]),
                    "final_loss": float(history.history["loss"][-1]),
                    "final_accuracy": float(history.history["accuracy"][-1]),
                }

                if "val_loss" in history.history:
                    result["final_val_loss"] = float(history.history["val_loss"][-1])
                    result["final_val_accuracy"] = float(history.history["val_accuracy"][-1])

                self.training_history.append(result)
                return result

            except Exception as e:
                logger.error(f"Training error: {e}")
                return {"error": str(e)}

    def predict(self, image_path):
        if self.model is None:
            return {"error": "No model trained yet"}

        img_array = self._preprocess_image(image_path)
        if img_array is None:
            return {"error": "Could not process image"}

        img_batch = np.expand_dims(img_array, axis=0)
        predictions = self.model.predict(img_batch, verbose=0)
        predicted_class_idx = int(np.argmax(predictions[0]))
        confidence = float(predictions[0][predicted_class_idx])

        all_predictions = {
            self.class_names[i]: float(predictions[0][i])
            for i in range(len(self.class_names))
        }

        return {
            "predicted_class": self.class_names[predicted_class_idx],
            "confidence": confidence,
            "all_predictions": all_predictions,
        }

    def add_training_example(self, image_path, label, contributor=None):
        label = self._sanitize_label(label)
        if not label:
            return {"error": "Invalid label"}

        if not self._validate_image(image_path):
            return {"error": "Invalid image file"}

        class_dir = os.path.join(DATA_FOLDER, label)
        os.makedirs(class_dir, exist_ok=True)

        filename = f"{uuid.uuid4().hex}.png"
        dest_path = os.path.join(class_dir, filename)

        img = Image.open(image_path).convert("RGB")
        img = img.resize((IMG_WIDTH, IMG_HEIGHT))
        img.save(dest_path)

        self.metadata["total_contributions"] = self.metadata.get("total_contributions", 0) + 1
        if contributor and contributor not in self.metadata.get("contributors", []):
            self.metadata.setdefault("contributors", []).append(contributor)
        self._save_metadata()

        self.contribution_log.append({
            "label": label,
            "contributor": contributor,
            "timestamp": datetime.now().isoformat(),
            "file": dest_path,
        })

        return {
            "status": "success",
            "label": label,
            "saved_path": dest_path,
            "total_contributions": self.metadata["total_contributions"],
        }


pipeline = TrainingPipeline()


def allowed_file(filename, allowed_extensions):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in allowed_extensions


@app.route("/api/health", methods=["GET"])
def health_check():
    return jsonify({
        "status": "healthy",
        "model_loaded": pipeline.model is not None,
        "model_version": pipeline.metadata.get("model_version", "none"),
        "class_names": pipeline.class_names,
        "total_contributions": pipeline.metadata.get("total_contributions", 0),
        "total_samples": pipeline.metadata.get("total_samples", 0),
        "contributors_count": len(pipeline.metadata.get("contributors", [])),
    })


@app.route("/api/upload/csv", methods=["POST"])
def upload_csv():
    if "file" not in request.files:
        return jsonify({"error": "No file provided"}), 400

    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "No file selected"}), 400

    if not allowed_file(file.filename, ALLOWED_CSV_EXTENSIONS):
        return jsonify({"error": "Only CSV files are allowed"}), 400

    filename = secure_filename(file.filename)
    upload_id = uuid.uuid4().hex
    upload_dir = os.path.join(UPLOAD_FOLDER, upload_id)
    os.makedirs(upload_dir, exist_ok=True)
    filepath = os.path.join(upload_dir, filename)
    file.save(filepath)

    image_column = request.form.get("image_column", "image_path")
    label_column = request.form.get("label_column", "label")

    if "images" in request.files:
        image_files = request.files.getlist("images")
        for img_file in image_files:
            if img_file.filename and allowed_file(img_file.filename, ALLOWED_IMAGE_EXTENSIONS):
                img_filename = secure_filename(img_file.filename)
                img_file.save(os.path.join(upload_dir, img_filename))

    images, labels, error = pipeline.load_csv_dataset(
        filepath, image_column=image_column, label_column=label_column
    )

    if error:
        shutil.rmtree(upload_dir, ignore_errors=True)
        return jsonify({"error": error}), 400

    return jsonify({
        "status": "success",
        "upload_id": upload_id,
        "num_samples": len(images),
        "classes_found": list(set(labels)),
        "message": f"Loaded {len(images)} samples. Use /api/train/{upload_id} to start training.",
    })


@app.route("/api/train/<upload_id>", methods=["POST"])
def train_from_upload(upload_id):
    upload_dir = os.path.join(UPLOAD_FOLDER, upload_id)
    upload_dir = os.path.realpath(upload_dir)
    if not upload_dir.startswith(os.path.realpath(UPLOAD_FOLDER)):
        return jsonify({"error": "Invalid upload ID"}), 400
    if not os.path.exists(upload_dir):
        return jsonify({"error": "Upload not found"}), 404

    csv_files = [f for f in os.listdir(upload_dir) if f.endswith(".csv")]
    if not csv_files:
        return jsonify({"error": "No CSV file found in upload"}), 400

    csv_path = os.path.join(upload_dir, csv_files[0])
    image_column = request.json.get("image_column", "image_path") if request.is_json else "image_path"
    label_column = request.json.get("label_column", "label") if request.is_json else "label"
    epochs = int(request.json.get("epochs", DEFAULT_EPOCHS)) if request.is_json else DEFAULT_EPOCHS
    contributor = request.json.get("contributor", "anonymous") if request.is_json else "anonymous"

    epochs = min(max(epochs, 1), 100)

    images, labels, error = pipeline.load_csv_dataset(
        csv_path, image_column=image_column, label_column=label_column
    )

    if error:
        return jsonify({"error": error}), 400

    result = pipeline.train(images, labels, epochs=epochs, contributor=contributor)

    if "error" in result:
        return jsonify(result), 400

    return jsonify(result)


@app.route("/api/train/directory", methods=["POST"])
def train_from_directory():
    epochs = int(request.json.get("epochs", DEFAULT_EPOCHS)) if request.is_json else DEFAULT_EPOCHS
    contributor = request.json.get("contributor", "anonymous") if request.is_json else "anonymous"
    epochs = min(max(epochs, 1), 100)

    images, labels, error = pipeline.load_directory_dataset()

    if error:
        return jsonify({"error": error}), 400

    if len(images) == 0:
        return jsonify({"error": "No training data found in directory"}), 400

    result = pipeline.train(images, labels, epochs=epochs, contributor=contributor)

    if "error" in result:
        return jsonify(result), 400

    return jsonify(result)


@app.route("/api/contribute", methods=["POST"])
def contribute_training_example():
    if "image" not in request.files:
        return jsonify({"error": "No image file provided"}), 400

    if "label" not in request.form:
        return jsonify({"error": "No label provided"}), 400

    file = request.files["image"]
    label = request.form["label"]
    contributor = request.form.get("contributor", "anonymous")

    if file.filename == "":
        return jsonify({"error": "No file selected"}), 400

    if not allowed_file(file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({"error": "Only image files (png, jpg, jpeg, bmp, gif) are allowed"}), 400

    temp_path = os.path.join(UPLOAD_FOLDER, f"temp_{uuid.uuid4().hex}")
    file.save(temp_path)

    try:
        result = pipeline.add_training_example(temp_path, label, contributor=contributor)
    finally:
        if os.path.exists(temp_path):
            os.remove(temp_path)

    if "error" in result:
        return jsonify(result), 400

    return jsonify(result)


@app.route("/api/contribute/batch", methods=["POST"])
def contribute_batch():
    if "images" not in request.files:
        return jsonify({"error": "No image files provided"}), 400

    if "labels" not in request.form:
        return jsonify({"error": "No labels provided. Provide comma-separated labels."}), 400

    files = request.files.getlist("images")
    labels = request.form["labels"].split(",")
    contributor = request.form.get("contributor", "anonymous")

    if len(files) != len(labels):
        return jsonify({
            "error": f"Number of images ({len(files)}) doesn't match number of labels ({len(labels)})"
        }), 400

    results = []
    success_count = 0
    error_count = 0

    for file, label in zip(files, labels):
        label = label.strip()

        if not file.filename or not allowed_file(file.filename, ALLOWED_IMAGE_EXTENSIONS):
            results.append({"file": file.filename, "error": "Invalid file"})
            error_count += 1
            continue

        temp_path = os.path.join(UPLOAD_FOLDER, f"temp_{uuid.uuid4().hex}")
        file.save(temp_path)

        try:
            result = pipeline.add_training_example(temp_path, label, contributor=contributor)
            results.append({"file": file.filename, **result})
            if "error" not in result:
                success_count += 1
            else:
                error_count += 1
        finally:
            if os.path.exists(temp_path):
                os.remove(temp_path)

    return jsonify({
        "total": len(files),
        "success": success_count,
        "errors": error_count,
        "details": results,
    })


@app.route("/api/predict", methods=["POST"])
def predict():
    if "image" not in request.files:
        return jsonify({"error": "No image file provided"}), 400

    file = request.files["image"]

    if file.filename == "":
        return jsonify({"error": "No file selected"}), 400

    if not allowed_file(file.filename, ALLOWED_IMAGE_EXTENSIONS):
        return jsonify({"error": "Only image files are allowed"}), 400

    temp_path = os.path.join(UPLOAD_FOLDER, f"predict_{uuid.uuid4().hex}")
    file.save(temp_path)

    try:
        result = pipeline.predict(temp_path)
    finally:
        if os.path.exists(temp_path):
            os.remove(temp_path)

    if "error" in result:
        return jsonify(result), 400

    return jsonify(result)


