@app.route("/api/data/stats", methods=["GET"])
def data_stats():
    stats = {}
    total = 0

    if os.path.exists(DATA_FOLDER):
        for class_name in sorted(os.listdir(DATA_FOLDER)):
            class_dir = os.path.join(DATA_FOLDER, class_name)
            if os.path.isdir(class_dir):
                count = len([
                    f for f in os.listdir(class_dir)
                    if "." in f and f.rsplit(".", 1)[1].lower() in ALLOWED_IMAGE_EXTENSIONS
                ])
                stats[class_name] = count
                total += count

    return jsonify({
        "classes": stats,
        "num_classes": len(stats),
        "total_samples": total,
    })


@app.route("/api/retrain", methods=["POST"])
def retrain():
    epochs = int(request.json.get("epochs", DEFAULT_EPOCHS)) if request.is_json else DEFAULT_EPOCHS
    contributor = request.json.get("contributor", "system") if request.is_json else "system"
    epochs = min(max(epochs, 1), 100)

    images, labels, error = pipeline.load_directory_dataset()

    if error or len(images) == 0:
        return jsonify({"error": error or "No training data available"}), 400

    result = pipeline.train(images, labels, epochs=epochs, contributor=contributor)

    if "error" in result:
        return jsonify(result), 400

    return jsonify(result)


